const config = {
  toolRegistry: [
    {
      toolName: 'sprintHealthcheck',
      workflowId: '__REGISTRY__:MoMo AI Assistant Tool Sprint Healthcheck',
      enabled: true,
      matchers: [
        { pattern: 'check\\s+sprint', flags: 'i' },
        {
          pattern: 'status\\s+sprint',
          flags: 'i',
          args: {
            additionalDestinations: [{ type: 'pushGoogleChat' }],
          },
        },
        { pattern: 'sprint\\s+status', flags: 'i' },
        { pattern: 'healthcheck', flags: 'i' },
      ],
    },
    {
      toolName: 'demoCommand',
      workflowId: '__REGISTRY__:MoMo AI Assistant Tool Demo Commands',
      enabled: true,
      matchers: [
        {
          pattern: 'release\\s+sprint|close\\s+sprint|release\\s+status',
          flags: 'i',
          args: { commandType: 'release_sprint' },
        },
        {
          pattern: '(^|\\b)(approve|ok|dong y|đồng ý|xac nhan|xác nhận)(\\b|$)',
          flags: 'i',
          args: { commandType: 'approve' },
        },
        {
          pattern: '(^|\\b)(reject|tu choi|từ chối)(\\b|$)',
          flags: 'i',
          args: { commandType: 'reject' },
        },
        {
          pattern: '(^|\\b)(cancel|huy|hủy)(\\b|$)',
          flags: 'i',
          args: { commandType: 'cancel' },
        },
      ],
    },
  ],
};

return [
  {
    json: {
      ...$json,
      config,
    },
  },
];

const input = $('Config Main').first().json || {};
const config = input.config || {};
const toolRegistry = Array.isArray(config.toolRegistry) ? config.toolRegistry : [];
const commandText = String(input.commandText || '').trim();

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function toObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function mergeObjects(...objects) {
  return objects.reduce((acc, object) => ({ ...acc, ...toObject(object) }), {});
}

function buildRegex(matcher) {
  const pattern = toText(matcher?.pattern || '');
  if (!pattern) return null;

  try {
    return new RegExp(pattern, toText(matcher?.flags || 'i') || 'i');
  } catch (error) {
    return null;
  }
}

const incomingArgs = toObject(input.args);
let resolvedTool = null;

for (const tool of toolRegistry) {
  if (!tool || tool.enabled === false) continue;
  const matchers = Array.isArray(tool.matchers) ? tool.matchers : [];

  for (const matcher of matchers) {
    const regex = buildRegex(matcher);
    if (!regex || !regex.test(commandText)) continue;

    resolvedTool = {
      toolName: toText(tool.toolName),
      workflowId: toText(tool.workflowId),
      args: mergeObjects(incomingArgs, tool.args, matcher.args),
    };
    break;
  }

  if (resolvedTool) break;
}

const toolInput = {
  triggerSource: toText(input.triggerSource || 'chat'),
  commandText,
  channel: toText(input.channel || 'googleChat'),
  sessionId: toText(input.sessionId),
  spaceId: toText(input.spaceId),
  threadKey: toText(input.threadKey),
  actorId: toText(input.actorId),
  actorDisplayName: toText(input.actorDisplayName),
  args: toObject(resolvedTool?.args || incomingArgs),
};

return [
  {
    json: {
      commandText,
      resolutionStatus: resolvedTool ? 'matched' : 'unsupported',
      resolvedTool,
      toolInput,
      args: toolInput.args,
    },
  },
];

const input = $('Resolve Routed Tool').first().json || {};
const commandText = String(input.commandText || '').trim();
const additionalDestinations = Array.isArray(input.args?.additionalDestinations)
  ? input.args.additionalDestinations
  : [];
const resultText = commandText
  ? `Hiện mình chưa map command "${commandText}" vào business tool nào cả.`
  : 'Hiện mình chưa nhận ra command nào để route sang business tool.';

function normalizeDestinations(rawDestinations) {
  if (!Array.isArray(rawDestinations)) return [];

  const normalized = [];
  const seen = new Set();
  for (const rawDestination of rawDestinations) {
    const type = typeof rawDestination === 'string'
      ? rawDestination.trim()
      : String(rawDestination?.type || '').trim();

    if (!type || seen.has(type)) continue;
    seen.add(type);
    normalized.push({ type });
  }

  return normalized;
}

const destinations = normalizeDestinations([
  { type: 'reply' },
  ...additionalDestinations,
]);
const destinationTypes = destinations.map((destination) => destination.type);

return [{
  json: {
    toolName: 'assistantCommandRouter',
    resultText,
    deliveryPlan: {
      thread: {
        mode: 'singleThread',
        threadKeyHint: 'assistant-router-unsupported',
      },
      destinations,
      messages: [
        {
          messageKey: 'unsupported',
          type: 'text',
          destinations: destinationTypes,
          payload: { text: resultText },
        },
      ],
    },
  },
}];
